// Define connection pool at package level
type SchedulerConnPool struct {
    addr     string
    maxSize  int
    conns    chan net.Conn
    mu       sync.RWMutex
}

func NewSchedulerConnPool(addr string, size int) *SchedulerConnPool {
    return &SchedulerConnPool{
        addr:    addr,
        maxSize: size,
        conns:   make(chan net.Conn, size),
    }
}

func (p *SchedulerConnPool) Get(ctx context.Context) (net.Conn, error) {
    select {
    case conn := <-p.conns:
        // Validate connection
        if conn != nil {
            return conn, nil
        }
    case <-ctx.Done():
        return nil, ctx.Err()
    default:
    }

    // Create new connection with timeouts
    dialer := &net.Dialer{
        Timeout:   5 * time.Second,
        KeepAlive: 30 * time.Second,
    }
    return dialer.DialContext(ctx, "tcp", p.addr)
}

func (p *SchedulerConnPool) Put(conn net.Conn) {
    select {
    case p.conns <- conn:
    default:
        conn.Close()
    }
}

func notifySchedulerWithRetry(ctx context.Context, pool *SchedulerConnPool, msg []byte) error {
    maxRetries := 3
    backoffDurations := []time.Duration{100 * time.Millisecond, 200 * time.Millisecond, 400 * time.Millisecond}

    var lastErr error
    for attempt := 0; attempt <= maxRetries; attempt++ {
        if attempt > 0 {
            select {
            case <-ctx.Done():
                return ctx.Err()
            case <-time.After(backoffDurations[attempt-1]):
            }
        }

        conn, err := pool.Get(ctx)
        if err != nil {
            lastErr = err
            continue
        }
        defer pool.Put(conn)

        // Set write deadline
        if deadline, ok := ctx.Deadline(); ok {
            conn.SetWriteDeadline(deadline)
        } else {
            conn.SetWriteDeadline(time.Now().Add(10 * time.Second))
        }

        _, err = conn.Write(msg)
        if err == nil || err == io.EOF {
            return err
        }
        lastErr = err
    }

    return fmt.Errorf("failed to notify scheduler after %d retries: %w", maxRetries, lastErr)
}

type SchedulerHealthChecker struct {
    addr          string
    lastCheck     time.Time
    lastHealthy   bool
    cacheDuration time.Duration
    mu            sync.RWMutex
}

func (h *SchedulerHealthChecker) IsHealthy(ctx context.Context) bool {
    h.mu.RLock()
    if time.Since(h.lastCheck) < h.cacheDuration && h.lastHealthy {
        h.mu.RUnlock()
        return true
    }
    h.mu.RUnlock()

    // Perform health check
    dialer := &net.Dialer{Timeout: 2 * time.Second}
    conn, err := dialer.DialContext(ctx, "tcp", h.addr)
    if err != nil {
        h.mu.Lock()
        h.lastHealthy = false
        h.lastCheck = time.Now()
        h.mu.Unlock()
        return false
    }
    conn.Close()

    h.mu.Lock()
    h.lastHealthy = true
    h.lastCheck = time.Now()
    h.mu.Unlock()
    return true
}

